/**
 * Reads the real `deploy-assets/library/<folderName>/<agdaLibFile>` for
 * every currently-selected library and writes
 * `deploy-assets/generated-libraries.mjs`, mapping each `folderName` to
 * the `includeSubpath`/`libraryName` parsed directly out of that file
 * (`include:`/`name:`).
 *
 * deploy.config.mjs no longer hand-declares includeSubpath/libraryName —
 * generating them from the real .agda-lib content means they can never
 * drift from what the file actually says.
 *
 * The generated file is a plain ES module, imported directly by
 * src/lib/runtime/interface.ts at build time (Vite inlines it into the
 * compiled bundle — no runtime fetch, no need to make
 * resolveProfileLibraries() async). It's gitignored, like everything else
 * this script reads from (deploy-assets/library/) — which means it won't
 * exist yet on a fresh checkout, before deploy-assets/library/ is
 * populated. A library whose .agda-lib isn't there yet is skipped with a
 * warning rather than failing the whole run, so `predev`/`precheck`/
 * `prebuild` (package.json) can always run this first and guarantee the
 * file exists (even if empty) for interface.ts's import to resolve —
 * letting `npm run check`/`npm run build` succeed without requiring
 * deploy-assets/library/ to be populated first (e.g. in CI's
 * check-and-build job, which deliberately skips auto-configure/setup to
 * stay fast). `npm run setup` itself already only reaches this script
 * after deploy-assets/print-required-files.mjs has confirmed every
 * required .agda-lib is genuinely present, so in that path nothing is
 * ever actually skipped.
 *
 * Usage: node deploy-assets/generate-library-info.mjs
 */

import { readFile, writeFile } from 'node:fs/promises'
import { join, relative } from 'node:path'
import { REPO_ROOT, getSelectedLibraries } from './resolve-deploy-config.mjs'
import { parseAgdaLibInclude, parseAgdaLibName } from './agda-lib-utils.mjs'

const DEPLOY_ASSETS = join(REPO_ROOT, 'deploy-assets')
const OUT_PATH = join(DEPLOY_ASSETS, 'generated-libraries.mjs')

async function main() {
  const info = {}
  let skipped = 0
  for (const lib of getSelectedLibraries()) {
    const agdaLibPath = join(DEPLOY_ASSETS, 'library', lib.folderName, lib.agdaLibFile)
    let src
    try {
      src = await readFile(agdaLibPath, 'utf8')
    } catch {
      console.warn(`  skipping ${lib.folderName}: could not read ${relative(REPO_ROOT, agdaLibPath)} (place this library's raw source — see deploy-assets/README.md — then re-run \`npm run setup\`)`)
      skipped++
      continue
    }
    info[lib.folderName] = {
      includeSubpath: parseAgdaLibInclude(src),
      libraryName: parseAgdaLibName(src),
    }
  }

  const lines = [
    '// Generated by deploy-assets/generate-library-info.mjs — do not edit by hand.',
    '// Re-run `npm run setup` after changing deploy.config.mjs or any placed .agda-lib file.',
    '',
    // Without this, TS would infer a literal-keys-only type from whatever
    // happens to be in `info` right now — fine when it's the real,
    // fully-populated content, but when this file is just the
    // empty/partial stub a missing deploy-assets/library/ leaves behind
    // (see this script's header comment), TS would infer `{}`, making
    // every lookup in src/lib/runtime/interface.ts resolve to `never`
    // instead of `undefined` and fail to typecheck.
    '/** @type {Record<string, { includeSubpath: string, libraryName: string }>} */',
    `export const GENERATED_LIBRARY_INFO = ${JSON.stringify(info, null, 2)}`,
    '',
  ]
  await writeFile(OUT_PATH, lines.join('\n'))
  console.log(`Wrote ${Object.keys(info).length} librar${Object.keys(info).length === 1 ? 'y' : 'ies'}${skipped > 0 ? ` (${skipped} skipped)` : ''} to ${relative(REPO_ROOT, OUT_PATH)}`)
}

main().catch(err => { console.error(err); process.exit(1) })
